// TestBatchEvaluationSuccess tests batch evaluation with multiple requests.
func TestBatchEvaluationSuccess(t *testing.T) {
	store := newMockStore()

	// Setup multiple flags
	store.flags["default/flag-1"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "flag-1",
		Enabled:      true,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		CreatedAt:    timestamppb.Now(),
		UpdatedAt:    timestamppb.Now(),
	}
	store.rollouts["default/flag-1"] = []*storage.EvaluationRollout{}

	store.flags["default/flag-2"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "flag-2",
		Enabled:      false,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		CreatedAt:    timestamppb.Now(),
		UpdatedAt:    timestamppb.Now(),
	}
	store.rollouts["default/flag-2"] = []*storage.EvaluationRollout{}

	server := setupServer(t, store)
	defer server.Close()

	batchReq := &rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-request-1",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "req-1",
				NamespaceKey: "default",
				FlagKey:      "flag-1",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
			{
				RequestId:    "req-2",
				NamespaceKey: "default",
				FlagKey:      "flag-2",
				EntityId:     "user-2",
				Context:      map[string]string{},
			},
		},
	}

	reqBody, err := protojson.Marshal(batchReq)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/batch", server.URL),
		"application/json",
		bytes.NewReader(reqBody),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200, got %d", resp.StatusCode)
	}

	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var batchResp rpcevaluation.BatchEvaluationResponse
	err = protojson.Unmarshal(body, &batchResp)
	require.NoError(t, err)

	// Verify batch response has 2 responses
	assert.Equal(t, 2, len(batchResp.Responses))

	// Check first response (flag-1 enabled)
	if batchResp.Responses[0].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Fatal("expected boolean response type for first response")
	}

	boolResp1 := batchResp.Responses[0].GetBooleanResponse()
	assert.NotNil(t, boolResp1)
	assert.True(t, boolResp1.Enabled)
	assert.Equal(t, "flag-1", boolResp1.FlagKey)

	// Check second response (flag-2 disabled)
	if batchResp.Responses[1].Type != rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE {
		t.Fatal("expected boolean response type for second response")
	}

	boolResp2 := batchResp.Responses[1].GetBooleanResponse()
	assert.NotNil(t, boolResp2)
	assert.False(t, boolResp2.Enabled)
	assert.Equal(t, "flag-2", boolResp2.FlagKey)
}

// TestBatchEvaluationWithNotFound tests batch evaluation including a non-existent flag.
func TestBatchEvaluationWithNotFound(t *testing.T) {
	store := newMockStore()

	// Setup one flag
	store.flags["default/flag-1"] = &flipt.Flag{
		NamespaceKey: "default",
		Key:          "flag-1",
		Enabled:      true,
		Type:         flipt.FlagType_BOOLEAN_FLAG_TYPE,
		CreatedAt:    timestamppb.Now(),
		UpdatedAt:    timestamppb.Now(),
	}
	store.rollouts["default/flag-1"] = []*storage.EvaluationRollout{}

	server := setupServer(t, store)
	defer server.Close()

	batchReq := &rpcevaluation.BatchEvaluationRequest{
		RequestId: "batch-request-2",
		Requests: []*rpcevaluation.EvaluationRequest{
			{
				RequestId:    "req-1",
				NamespaceKey: "default",
				FlagKey:      "flag-1",
				EntityId:     "user-1",
				Context:      map[string]string{},
			},
			{
				RequestId:    "req-2",
				NamespaceKey: "default",
				FlagKey:      "nonexistent-flag",
				EntityId:     "user-2",
				Context:      map[string]string{},
			},
		},
	}

	reqBody, err := protojson.Marshal(batchReq)
	require.NoError(t, err)

	resp, err := http.Post(
		fmt.Sprintf("%s/evaluate/v1/batch", server.URL),
		"application/json",
		bytes.NewReader(reqBody),
	)
	require.NoError(t, err)
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("expected status 200, got %d", resp.StatusCode)
	}

	body, err := io.ReadAll(resp.Body)
	require.NoError(t, err)

	var batchResp rpcevaluation.BatchEvaluationResponse
	err = protojson.Unmarshal(body, &batchResp)
	require.NoError(t, err)

	// Should have 2 responses
	assert.Equal(t, 2, len(batchResp.Responses))

	// First response should be successful
	assert.Equal(t, rpcevaluation.EvaluationResponseType_BOOLEAN_EVALUATION_RESPONSE_TYPE, batchResp.Responses[0].Type)

	// Second response should be error
	if batchResp.Responses[1].Type != rpcevaluation.EvaluationResponseType_ERROR_EVALUATION_RESPONSE_TYPE {
		t.Fatalf("expected error response type for second response, got %v", batchResp.Responses[1].Type)
	}

	errResp := batchResp.Responses[1].GetErrorResponse()
	assert.NotNil(t, errResp)
	assert.Equal(t, "nonexistent-flag", errResp.FlagKey)
	assert.Equal(t, "default", errResp.NamespaceKey)
	assert.Equal(t, rpcevaluation.ErrorEvaluationReason_NOT_FOUND_ERROR_EVALUATION_REASON, errResp.Reason)
}

